class MessageDispatcher:
    def __init__(self) -> None:
        self._handlers: Dict[str, Callable[[Dict[str, Any], Dict[str, Any]], Any]] = {}

    def register(self, message_type: str) -> Callable:
        def decorator(func: Callable[[Dict[str, Any], Dict[str, Any]], Any]) -> Callable:
            self._handlers[message_type] = func
            return func
        return decorator

    def dispatch(self, payload: Dict[str, Any], raw_message: Dict[str, Any]) -> Any:
        message_type = payload.get("type")
